public boolean validateParameters()
{
   boolean     validation = true;

    if (fromDateValue.dateValue() == dateNull())
    {
        validation = warning("From Date must be filled in");
    }

    if (toDateValue.dateValue() == dateNull())
    {
        validation = warning("To Date must be filled in");
    }

   return validation;
}
